// 数字排序段落
<template>
<div v-if="isShow()" class="serial-number last">
  <div v-for="(item, i) in content" :key="i">
    <p :style="{'text-indent': tab + 'rem'}">
      <span class="l">{{ i + 1 }}.</span>
      <span class="r">{{ item }}</span>
    </p>
  </div>
</div>
</template>

<script>
export default {
  name: 'serial-number',
  data() {
   return {
     number: 0
   }
  },
  props: {
    content: Array,
    tab: {
      type: Number,
      default: 2
    }
  },
  methods: {
    isShow() {
      if(this.content == undefined) {
        return false
      } else {
        return true
      }
    }
  }
}
</script>

<style lang="less" scoped>
.serial-number {
  margin-bottom: 20px;
  p {
    padding-bottom: 3px;
    .l {
      width: 40px;
    }
    .r {
      margin-left: 10px;
      word-break: break-all;
    }
  }
}

</style>