import { createApp } from 'vue'
import App from './App.vue'
import './registerServiceWorker'
import router from './router'
import store from './store'

// 全局 css 类
import 'assets/css/index.less'

// 全局组件
import serialNumber from 'common/serial-number.vue' // serialNumber 文档编号
import lv1 from 'common/nav/left-bar/lv1.vue' // 语言、框架
import lv2 from 'common/nav/left-bar/lv2.vue' // 技术分类
import lv3 from 'common/nav/left-bar/lv3.vue' // 技术细分（可直接陈述）
