const Intro = {
  state: {
    working: {
      i: 0,
      max: 1
    }
  },
  mutations: {
    next(state:any) {
      state.working.i++
      if(state.working.i > state.working.max) {
        state.working.i = 0
      }
    },
    back(state:any) {
      state.working.i--
      if(state.working.i < 0) {
        state.working.i = state.working.max
      }
    }
  }
}

export default Intro