// 旋转三角图标
<template>
  <span class="ico icon-play3" @click="rotate()" :style="rotateStyle"/>
</template>

<script>
export default {
  name: 'ico-rotate',
  data() {
    return {
      angle: 0,
      rotateStyle: {},
    }
  },
  methods: {
    // 旋转事件
    rotate() {
      if(this.angle == 0) {
        this.angle = 90;
        this.rotateStyle = {
          transition: 'transform .2s',
          transform: 'rotate(' + this.angle + 'deg)',
          opacity: 1,
          textShadow: '1px 1px 2px rgb(100, 100, 100, .8)'
        }
      } else {
        this.angle = 0;
        this.rotateStyle = {
          transition: 'transform .6s',
          transform: 'rotate(' + this.angle + 'deg)',
          opacity: 1,
          textShadow: '1px 1px 1px rgba(100, 100, 100, .2)'
        }
      }
    }
  }
}
</script>

<style lang="less" scoped>
.ico {
  // 围绕中心点旋转
  transform-origin: center;
  display: inline-block;
  color: @qing;
  opacity: .3;
  cursor: pointer;
}
</style>