// 小屏头部
<template>
<div id="min-nav" @click.stop v-if="$store.state.min_nav">
  <h4>
    <span class="ico icon-list" :class="{luminescence: luminescence}" @click="change()" />
    <span>{{ $store.state.min_nav_title }}</span>
  </h4>
</div>
</template>

<script>
export default {
  name: 'min-nav',
  data() {
    return {
      isChange: true,
      luminescence: false
    }
  },
  methods: {
    // 小导航点击开关
    change() {
      // 防抖设置
      if(this.isChange) {
        this.isChange = false
        this.$store.commit('min_nav_body_switch')
        setTimeout(() => {
          // 等待400毫秒，动画执行完毕
          this.isChange = true
        }, 400)
      }
      // 发光
      if(!this.luminescence) {
        this.luminescence = true
        setTimeout(() => {
          // 亮起一段时间后熄灭
          // 每次单击亮起400毫秒
          this.luminescence = false
        }, 400)
      }
    }
  }
}
</script>

<style lang="less" scoped>
#min-nav {
  width: 100%;
  height: 100%;
  line-height: 80px;
  margin-left: 20px;
}
.ico {
  cursor: pointer;
  padding: 10px 11px;
  margin-right: 10px;
  border-radius: 5px;
  position: relative;
  // 微调
  top: 1px;
  transition: 0.3s all;
}
.luminescence {
  background-color: rgba(255, 255, 255, 0.2);
  box-shadow: -2px -2px 4px rgba(255, 255, 255, 0.5);
}
</style>