// 四级 陈述
<template>
<div class="lv4" @click="goto()" @mouseover="isIn = true" @mouseleave="isIn = false">
  <div class="text" :class="{text_hover: isIn}">
    {{ text }}
  </div>
</div>
</template>

<script>
import jump from 'assets/js/jump.js'

export default {
  name: 'lv4',
  props: {
    text: String,
    to: {
      type: String,
      default: '/404'
    },
    lv1_index: Number,
    lv2_index: Number,
    lv3_index: Number,
    identifier: String,
  },
  data() {
    return {
      isIn: false
    }
  },
  mounted() {
    if (this.$route.query.id != undefined) {
      this.$store.commit('git_lv4_id', this.$route.query.id)
      this.$store.commit('study_open')
    }
  },
  methods: {
    goto() { // 前往目标路由
      this.$router.push({
        path: this.to,
        query: { 
          lv1: this.lv1_index, 
          lv2: this.lv2_index, 
          lv3: this.lv3_index, 
          id: this.identifier 
        } 
      })

      this.enterRouter()
    },
    // 点击路由跳转后
    enterRouter() {
      // 提交当前路由
      this.$store.commit('study_git', this.to)
      // 提交当前等级信息
      this.$store.commit('enter_lv4', {
          lv1_index: this.lv1_index,
          lv2_index: this.lv2_index,
          lv3_index: this.lv3_index,
          id: this.identifier
        }
      )
      // 根据状态执行
      if(this.$store.getters.lv) {
        // 如果是同界面，直接执行跳转
        jump(this.$store.getters.lv4_id)
      } else {
        // 如果是异界面
      }
    },
    close() {
      // 如果是小导航模式，可以点击关闭菜单栏
      if(this.$store.state.min_nav) {
        // 同小导航透明遮罩层事件
        this.$store.commit('min_nav_body_change', false)
      }
    }
  }
}
</script>

<style lang="less" scoped>
.lv4 {
  width: calc(100% - 10px);
  border-left: 4px solid @qing;
  margin-left: 10px;
  padding-top: 6px;
  padding-bottom: 4px;
  transition: all .15s;
  cursor: pointer;
  &:hover {
    background-color: rgba(255, 255, 255, .44);
  }
  .text {
    font-size: 1rem;
    user-select: none;
    margin-left: 13px;
    color: black;
    text-decoration: none;
    overflow:hidden;
    text-overflow:ellipsis;
    white-space:nowrap;
    display: inline-block;
    transition: all .2s;
  }
  .text_hover {
    color: @lan;
    transform: translateX(5px);
  }
}

.lv4-enter-active {
  animation: lv4-in .2s;
}
.lv4-leave-active {
  animation: lv4-in .5s reverse;
}
@keyframes lv4-in {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
</style>