<template>
<div class="menu-cont">
  <div class="s-cont">
    <!-- vue3 新版路由语法 -->
    <router-view v-slot="{ Component }">
      <!-- keep-alive 可增属性 include 、 exclude 无属性时默认缓存所有路由 -->
      <!-- include="只缓存的组件名称1，名称2" exclude="[不缓存的组件名称1，名称2]" -->
      <keep-alive> 
        <component :is="Component" />
      </keep-alive>
    </router-view>
  </div>
</div>
