// 轮播图 背景
<template>
<transition name="ready">
  <div class="banner" v-if="isReady">
    <transition name="into">
      <img 
        class="picture"
        :src="src[i1]"
        :style="{ width: width }"
        v-show="isShow"
      >
    </transition>
    <transition name="into">
      <img 
        class="picture"
        :src="src[i2]"
        :style="{ width: width }"
        v-show="!isShow"
      >
    </transition>
  </div>
</transition>
</template>

<script setup>
import imgReady from 'ts/shopping/imgReady'
// import { defineEmits } from 'vue'
// emit有bug无法使用
// const emit = defineEmits(["ready"])

// const ready = () => {
//   emit("ready")
// }
</script>

<script>
export default {
  name: 'banner',
  data() {
    return {
      once: 20000, // 执行一次动画间隔
      time: 3000, // 动画时间，取最大值
      loop: -1, // 循环
      i1: 0, // 第一张图片的下标
      i2: 1, // 第二张图片的下标
      max: 2, // 最大图片张数
      isButton: true, // 按钮是否可以点击
      isShow: true, // 控制图片切换
      isReady: false, // 加载完毕后显示
      src: [],
      width: 0 + 'px',
      src_4k: [
        "https://z3.ax1x.com/2021/08/18/f7eCef.jpg",
        "https://z3.ax1x.com/2021/08/18/f7eiTS.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ePw8.jpg",
        "https://z3.ax1x.com/2021/08/18/f7epOP.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZzQI.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ekFg.jpg"
      ],
      src_2k: [
        "https://z3.ax1x.com/2021/08/18/f7ZhW9.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZqoD.jpg",
        "https://z3.ax1x.com/2021/08/18/f7Z4zR.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZIQ1.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZHeK.jpg",
        "https://z3.ax1x.com/2021/08/18/f7Zosx.jpg"
      ],
      src_1080p: [
        "https://z3.ax1x.com/2021/08/18/f7ZwGj.jpg",
        "https://z3.ax1x.com/2021/08/18/f7Z0Rs.jpg",
        "https://z3.ax1x.com/2021/08/18/f7Zss0.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZcZT.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZrMq.jpg",
        "https://z3.ax1x.com/2021/08/18/f7ZBzn.jpg"
      ]
    }
  },
  mounted() {
    setInterval(() => {
      this.i++
    }, 1000)

    // ！！可以写成一个对象，图片使用21:10的可以解决带鱼屏的显示问题

    // 查询当前显示器的宽度分辨率
    let w = window.screen.width
    // 查询当前显示器的高度分辨率
    let h = window.screen.height

    if(w < 1280) { // 移动设备，使用4k图片
      this.src = this.src_4k
      // 根据当前屏幕高度，获取图片宽度
      this.width = h / 0.5625 + 'px'
    } else if (w == 1280) { // 720p
      this.src = this.src_1080p
      this.width = 1280 + 'px'
    } else if (w <= 1920 && h <= 1080) {  // 1080p
      this.src = this.src_1080p
      this.width = 1920 + 'px'
    } else if (w <= 2560 && h <= 1440) { // 2k
      this.src = this.src_2k
      // 查询宽高比例
      if(h / w != .5625) { // 宽高比不为16:9
        // 根据当前屏幕高度，获取图片宽度
        this.width = h / 0.5625 + 'px'
      } else {
        this.width = 2560 + 'px'
      }
    } else if (w <= 3840 && h <= 2160) { // 4k
      this.src = this.src_4k
      // 查询宽高比例
      if(h / w != .5625) { // 宽高比不为16:9
        // 根据当前屏幕高度，获取图片宽度
        this.width = h / 0.5625 + 'px'
      } else {
        this.width = 3840 + 'px'
      }
    } else { // 大于标准4k
      this.src = this.src_4k
      // 查询宽高比例
      if(h / w != .5625) { // 宽高比不为16:9
        // 根据当前屏幕高度，获取图片宽度
        this.width = h / 0.5625 + 'px'
      } else {
        this.width = w + 'px'
      }
    }

    // 确认前两张图片加载好了图片以后
    new imgReady([this.src[0], this.src[1]])
    .load().then((src) => {
      // 淡入显示图片
      this.isReady = true;

      // 开始循环轮播图
      this.leave()
      // // 图片淡入完成以后，允许其他内容淡入
      // setTimeout(() => {
      //   this.ready()
      // }, 100)

      // 载入剩余的图片
      let surplus = []
      for (let index = 2; index < this.src.length; index++) {
        surplus.push(this.src[index])
      }
      new imgReady(surplus).load()
    })

    // 页面获得焦点时，继续轮播图
    window.onfocus = () => {
      this.$store.commit('on_off_change', true)
    }

    // 页面失去焦点时，停止轮播图
    window.onblur = () => {
      this.$store.commit('on_off_change', false)
    }
  },
  methods: {
    // 鼠标进入停止循环
    enter() {
      clearTimeout(this.loop)
    },
    // 鼠标离开继续循环
    leave() {
      this.loop = setInterval(() => {
        this.next()
      }, this.once)
    },
    // 淡入淡出切换
    into() {
      this.isShow = !this.isShow
    },
    // 下一张图片
    next() {
      // 如果当前按钮不可点击，退出方法
      if(this.isButton == false) {
        return
      }

      // 如果不允许轮播图执行，退出方法
      if(this.$store.state.banner.on_off == false) {
        return
      }
      
      new Promise(resolve => {
        // 执行动作，按钮不可点击
        this.isButton = false
        // 淡入淡出
        this.into()
        // 切换后，等待动画完成
        setTimeout(() => {
          // 下一步
          resolve()
        }, this.time)
      }).then(() => { 
        // 第一张图隐藏时执行src切换
        if(this.isShow == false) {
          // 另一个下标不超过图片最大值，本数组下标为另一个加一
          if(this.i2 < this.max) {
            this.i1 = this.i2 + 1
          } else { // 如果达到最大值，数组下标归零
            this.i1 = 0
          }
        } else { // 如果第一张图片正在显示，第二张图片开始切换
          if(this.i1 < this.max) {
            this.i2 = this.i1 + 1
          } else {
            this.i2 = 0
          }
        }

        // 执行动作完毕，按钮可点击
        this.isButton = true
      })
    }
  }
}
</script>

<style lang="less" scoped>
.banner {
  position: fixed;
  top: 0;
  left: 0;
  display: inline-block;
  width: 100%;
  height: 100%;
  z-index: -10000;
  overflow: hidden;
  .picture {
    user-select: none;
    z-index: -10000;
    position: absolute;
