    opacity: 1;
  }
}

.into-enter-active {
  animation: into-in 3s;
}
.into-leave-active {
  animation: into-to 1.5s;
}
@keyframes into-in {
  0% {
    opacity: 0;
  }
  2% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
@keyframes into-to {
  0% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}
</style>