import $store from '@/store/index'

class widths {
  doc_width?: number

  WidthJudge() {
    // 获取页面宽度
    this.doc_width = window.innerWidth

    // 页面宽度小于等于 sm (768) 像素
    if(this.doc_width <= $store.state.sm) {
      this.navSm()
    } else {
      this.navSmClose()
    }

    // 页面宽度大于 md (768) 像素
    if (this.doc_width > $store.state.md) {
      this.navMd()
    } else {
      this.navMdClose()
    }

    // 页面宽度大于 lg (1200) 像素
    if (this.doc_width > $store.state.lg) {
      this.navLg()
    } else {
      this.navLgClose()
    }
  }

  navSm() {
    // 显示小导航
    $store.commit('min_nav_change', true)
    // 显示学习文档页面的小导航路由
    $store.commit('min_nav_router_change', true)
    // 隐藏大导航
    $store.commit('max_nav_change', false)
    // 隐藏小导航内容
    $store.commit('min_nav_body_change', false)
  }
  navSmClose() {
    // 隐藏小导航
    $store.commit('min_nav_change', false)
  }

  navMd() {
    // 显示学习文档小导航内容
    $store.commit('min_nav_body_change', true)
    // 显示大导航
    $store.commit('max_nav_change', true)
  }
  navMdClose() {
    // 隐藏学习文档页面的小导航路由
    $store.commit('min_nav_router_change', false)
  }

  navLg() {
    // 显示打印机按钮
    $store.commit('printer_change', true)
  }
  navLgClose() {
    // 隐藏打印机按钮
    $store.commit('printer_change', false)
  }
}

// 页面加载完成后，单独运行一次初始化
let dynamic = new widths()
dynamic.WidthJudge()

// 绑定到窗口宽度响应事件
window.addEventListener('resize', () => dynamic.WidthJudge(), false)