export default {
  name: 'App',
  components: {
    banner,
    navigation,
    pageCont
  },
  mounted() {
    let overlayscroll = OverlayScrollbars(document.body, {
      scrollbars: {
        visibility: "auto",
        autoHide: "move"
      },
      overflowBehavior : {
        x: "hidden",
        y: "scroll"
      }
    })
    this.$store.commit('app_scroll_change', overlayscroll)
  }
}
