// 三级 技术细分
<template>
<div class="lv3">
  <div class="text" @click="changeClose()" @mouseover="isIn = true" @mouseleave="isIn = false">
    <ico-rotate @click="rotate()" ref="icoRoutate" />
    <router-link
    @click.stop="enterRouter(); openClose()"
    :to="{path: to, query: { lv1: lv1_index, lv2: lv2_index, lv3: lv3_index, id: 'id-top' } }"
    class="router"
    :class="{router_hover: isIn}"
    ondragstart="return false"
    >{{ text }}</router-link>
  </div>
  
  <transition name="lv3">
    <div v-show="state">
      <slot />
    </div>
  </transition>
</div>
</template>

<script>
import jump from 'assets/js/jump.js'
import icoRotate from './ico-rotate.vue'

export default {
  name: 'lv3',
  data() {
    return {
      state: false,
      isIn: false
    }
  },
  components: {
    icoRotate
  },
  props: {
    text: String,
    to: {
      type: String,
      default: '/404'
    },
    lv1_index: Number,
    lv2_index: Number,
    lv3_index: Number
  },
  mounted() {
    // 如果没有地址栏参数，默认打开0菜单
    if ((this.$route.query.lv1 == undefined || this.$route.query.lv2 == undefined || this.$route.query.lv3 == undefined)
    && this.lv1_index == 0
    && this.lv2_index == 0
    && this.lv3_index == 0) {
      this.openClose();
    }
    // 如果是当前菜单
    if (this.$route.query.lv1 == this.lv1_index
    && this.$route.query.lv2 == this.lv2_index
    && this.$route.query.lv3 == this.lv3_index) {
      this.update();
      this.openClose();
    }
  },
  methods: {
    rotate() {
      this.$refs.icoRoutate.rotate();
    },
    stateChange() {
      this.state = !this.state
    },
    changeClose() {
      this.rotate()
      this.stateChange()
    },
    openClose() {
      if(this.state == false) {
        this.rotate()
        this.state = true
      }
    },
    update() {
      // 提交当前路由
      this.$store.commit('study_git', this.to)
      // 提交当前等级信息
      this.$store.commit('enter_lv4', {
          lv1_index: this.lv1_index,
          lv2_index: this.lv2_index,
          lv3_index: this.lv3_index,
          id: "id-top"
        }
      )
    },
    enterRouter() {
      this.update()
      // 根据状态执行
      if(this.$store.getters.lv) {
        // 如果是同界面，直接执行跳转
        jump('id-top')
      } else {
        // 如果是异界面
      }
    },
  }
}
</script>

<style lang="less" scoped>
.lv3 {
  padding-left: 26px;
  margin-bottom: 20px;
  .text {
    cursor: pointer;
    font-weight: 800;
    font-size: 1rem;
    user-select: none;
    padding-left: 5px;
    margin-bottom: 15px;
    .router {
      color: black;
      text-decoration: none;
      padding-left: 5px;
      display: inline-block;
      transition: all .2s;
    }
    .router_hover {
      color: @lan;
    }
  }
}

.lv3-enter-active {
  animation: lv3-in .2s;
}
.lv3-leave-active {
  animation: lv3-in .3s reverse;
}
@keyframes lv3-in {
  0% {
    margin-top: -15px;
    opacity: 0;
  }
  100% {
    margin-top: 0px;
    opacity: 1;
  }
}
</style>