// 路由组件
<template>
<div class="max-router-assembly flex-md">
  <router-link class="router" ondragstart="return false" :to="_to(message.url)">
    <h3>{{ message.title }}</h3>
  </router-link>
</div>
</template>

<script>
export default {
  name: 'max-nav-router',
  props: {
    message: Object
  },
  methods: {
    _to(url) {
      if(url === '/study') {
        return {
          path: this.$store.state.study,
          query: {
            lv1: this.$store.state.lv1,
            lv2: this.$store.state.lv2,
            lv3: this.$store.state.lv3,
            id: this.$store.state.lv4_id
          }
        }
      } else {
        return url
      }
    }
  }
}
</script>

