// 接收一个数组，数字内容为图片地址
class imgReady {
  length: number
  src: string[]
  all: object[]

  // 构造方法 关键字必须是 constructor
  constructor(src: string[]) {
    // 获取数据到对象
    this.src = src

    this.length = this.src.length

    // 先单独赋值，否则无法循环
    this.all = [this.ready(0)]

    // 循环将 Promise 对象赋给 all对象
    for(let i = 1; i < this.length; i++) {
      this.all.push(this.ready(i))
    }
  }

  ready(i: number) {
    let img = new Image()

    return new Promise(resolve => {
      img.onload = () => {
        resolve(this.src[i])
      }

      img.src = this.src[i]
    })
  }

  load() {
    // 外部使用.then()方法，返回一个字符串内容为原地址
    return Promise.all(this.all)
  }
}

export default imgReady