// 文档文字
<template>
  <p class="last" v-if="isShow()" :style="{'text-indent': tab + 'rem'}">
    <span>{{ text }}</span>
    <link-address :link="link" />
  </p>
</template>

<script>
import linkAddress from 'common/link-address.vue'

export default {
  name: 'doc',
  components: {
    linkAddress
  },
  props: {
    tab: {
      type: Number,
      default: 2
    },
    text: String,
    link: String,
  },
  methods: {
    isShow() {
      if(this.text == undefined) {
        return false
      } else {
        return true
      }
    }
  }
}
</script>

<style lang="less" scoped>
  p {
    margin-bottom: 20px;
    line-height: 26px;
  }
</style>