import { createStore } from 'vuex'
import banner from './banner'
import expo from './expo'
import ready from './ready'
import Intro from './Intro'
import OverlayScrollbars from 'overlayscrollbars' // 滚动条插件

export default createStore({
  state: {
    // sm 小于等于 768
    sm: 768,
    // md 大于 768
    md: 768,
    // lg 大于 1200
    lg: 1200,
    // 小导航是否显示
    min_nav: false,
    // 小导航路由跳转是否显示
    min_nav_router: false,
    // 小导航内容是否显示 同学习文档，页面左侧栏
    min_nav_body: false,
    // 小导航标题
    min_nav_title: '',
    // 大导航是否显示
    max_nav: false,
    // 是否是原界面
    lv: false,
    // 当前一级选项卡
    lv1: 0,
    // 新的一级选项卡
    lv1_new: 0,
    // 当前二级选项卡
    lv2: 0,
    // 新的二级选项卡
    lv2_new: 0,
    // 当前三级标题
    lv3: 0,
    // 新的三级标题
    lv3_new: 0,
    // 四级标题指向的id
    lv4_id: 'id-top',
    // 学习文档url
    study: '/study',
    // 打印机按钮
    printer: false,
    // app 滚动条
    app_scroll: {}
  },
  mutations: {
    // 小导航是否显示
    app_scroll_change(state, obj:object) {
      state.app_scroll = obj;
    },
    // 小导航是否显示
    min_nav_change(state, change:boolean) {
      state.min_nav = change;
    },
    // 小导航路由是否显示
    min_nav_router_change(state, change:boolean) { 
      state.min_nav_router = change;
    },
    // 小导航内容是否显示
    min_nav_body_change(state, change:boolean) {
      state.min_nav_body = change;
    },
    // 小导航开关切换
    min_nav_body_switch(state) {
      state.min_nav_body = !state.min_nav_body;
    },
    // 小导航标题文字切换
    min_nav_title_change(state, change:string) {
      state.min_nav_title = change;
    },
    // 大导航是否显示
    max_nav_change(state, change:boolean) {
      state.max_nav = change;
    },
    // 进入一个四级路由跳转
    enter_lv4(state, data:{
      lv1_index: number,
      lv2_index: number,
      lv3_index: number,
      id: string
    }) {
      // 将 key 序列提交
      state.lv1_new = data.lv1_index
      state.lv2_new = data.lv2_index
      state.lv3_new = data.lv3_index
      // 提交id
      state.lv4_id = data.id
      // 通过序号确认是否是原来的页面
      if(state.lv1 == state.lv1_new && state.lv2 == state.lv2_new && state.lv3 == state.lv3_new) {
        // 是原界面进行操作，执行原页面jump
        state.lv = true
      } else {
        // 是异界面进行操作，由异界面 activated() 生命周期函数执行跳转效果
        state.lv = false
      }
      // 操作完成后矫正当前二级、三级标题
      state.lv1 = state.lv1_new
      state.lv2 = state.lv2_new
      state.lv3 = state.lv3_new
    },
    // 单独提交 lv4_id
    git_lv4_id(state, id:string) {
      state.lv4_id = id
    },
    // 提交学习文档的路由地址
    study_git(state, url:string) {
      state.study = url
    },
    study_open(state) {
      // 每次重新进入学习文档页面，确认异界面，进行id跳转
      state.lv = false
    },
    // 打印机状态
    printer_change(state, b:boolean) {
      state.printer = b
    },
  },
  actions: {},
  getters: {
    // 获取当前是否是原来的页面状态
    lv(state) {
      return state.lv
    },
    lv4_id(state) {
      return state.lv4_id
    }
  },
  modules: {
    banner,
    expo,
    ready,
    Intro
  }
})