// 文档要点标题
<template>
  <div class="doc-topic" ref="topic" v-if="isShow()" :id="identifier">
    <h4 class="text" @click="t()" @mouseover="over()" @mouseleave="leave()">
      <span>{{ text }}</span>

      <span class="tips">
        <transition name="into">
          <span v-show="tips_isShow" class="ico icon-eject" />
        </transition>
      </span>
    </h4>
  </div>
</template>

<script>
import jump from 'assets/js/jump.js'

export default {
  name: 'doc-topic',
  data() {
    return {
      tips_isShow: false,
      timer: -1 // 存放计时器
    }
  },
  props: {
    text: String,
    identifier: String
  },
  activated() {
    // 进入路由，注册事件
    // id存在，即可注册
    // 滚动条移动像素
    if(this.identifier != undefined) {
      // 每毫秒执行一次
      this.timer = setInterval(() => {
        this.throttle()
      }, 300)
    }
  },
  deactivated() {
    // 离开路由，注销事件
    if(this.identifier != undefined) {
      clearTimeout(this.timer);
    }
  },
  methods: {
    // 根据标题距离屏幕顶端距离，决定query的id值
    throttle() {
      // 滚动条百分比
      let scorll = this.$store.state.app_scroll.scroll().ratio.y;
      // 容器高度
      let height = this.$refs.topic.parentElement.parentElement.parentElement.offsetHeight;
      // 元素本身距离浏览器顶端的距离
      let top = this.$refs.topic.offsetTop
      // 差值，单位：数字(像素)
      let c = scorll * height - top
      if(c < 250 && c > 0) {
        this.get_into(this.identifier)
      } else if (scorll == 0) {
        this.get_into("id-top")
      } else if (scorll == 1) {
        this.get_into("id-bottom")
      }
    },
    isShow() {
      if(this.text == undefined) {
        return false
      } else {
        return true
      }
    },
    // 跳转到
    t() {
      jump(this.identifier)
    },
    // 鼠标进入
    over() {
      this.tips_isShow = true
    },
    // 鼠标离开
    leave() {
      this.tips_isShow = false
    },
    // 进入了id
    get_into(_id) {
      // 无法获取menu-bar的层级值，只能通过状态管理获取
      this.$router.push({
        query: {
          lv1: this.$store.state.lv1,
          lv2: this.$store.state.lv2,
          lv3: this.$store.state.lv3,
          id: _id
        }
      })
    }
  }
}
</script>

