  // 字符间距
  letter-spacing: 1px;
  padding-top: @nav-h + 50px;
  margin-bottom: 20px;
  margin-top: -@nav-h;
  .text {
    padding-bottom: 10px;
    border-bottom: 2px solid rgba(0, 0, 0, 0);
    display: inline-block;
    cursor: pointer;
    transition: all .2s;
    &:hover {
      border-bottom: 2px solid @qing;
    }
    .tips {
      display: inline-block;
      text-align: right;
      font-weight: 800;
      width: 30px;
      color: @qing;
      // 微调距离
      position: relative;
      top: 3px;
    }
  }
}

.into-enter-active {
  animation: into-in .2s ;
}
.into-leave-active {
  animation: into-in .1s reverse;
}
@keyframes into-in {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
</style>