// 小屏导航
<template>
  <router-link class="min-router-assembly"
  @click="$store.commit('min_nav_body_switch')"
  v-for="(item, i) in message"
  :key="i"
  :to="_to(item.url)"
  ondragstart="return false"
  >{{ item.title }}</router-link>
</template>

<script>
export default {
  name: 'min-router-assembly',
  props: {
    message: Array
  },
  methods: {
    _to(url) {
      if(url === '/study') {
        return {
          path: this.$store.state.study,
          query: {
            lv1: this.$store.state.lv1,
            lv2: this.$store.state.lv2,
            lv3: this.$store.state.lv3,
            id: this.$store.state.lv4_id
          }
        }
      } else {
        return url
      }
    }
  }
}
</script>

