// 旋转按钮
<template>
  <span 
    @click="rotate()"
    :style="rotateStyle"
    :class="{qing: size_color}"
    class="ico icon-spinner9"
  />
</template>

<script>
export default {
  name: 'rotate',
  props: {
    size_color: {
      type: Boolean,
      default: false
    }
  },
  data() {
    return {
      r: true, 
      frequency: 0,
      rotateStyle: {}
    }
  },
  methods: {
    // 旋转事件
    rotate() {
      // 限制点击速度
      if(this.r) {
        this.r = false
        this.frequency++;

        this.rotateStyle = {
          transition: 'transform .5s',
          transform: 'rotate(' + this.frequency * 360 + 'deg)',
        }
        // 动画执行完成以后允许再次点击
        setTimeout(() => {
          this.r = true
        }, 500)
      }
    },
  },
}
</script>

<style lang="less" scoped>
.ico {
  user-select: none;
  cursor: pointer;
  color: @bai;
  width: 40px;
  height: 40px;
  z-index: 25;
  text-align: center;
  line-height: 40px;
  position: absolute;
  font-size: @h3;
}
.qing {
  color: @qing;
}
</style>