// 一级选择项 语言、框架
<template>
<div class="lv1">
  <div class="bgc-hover">
    <div class="text" @click="changeClose()" @mouseover="isIn = true" @mouseleave="isIn = false" :class="{text_hover: isIn}">
      <ico-rotate @click="rotate()" class="ico" ref="icoRoutate" />
      <span class="hand">{{ text }}</span>
    </div>

    <transition name="lv1">
      <div v-show="state">
        <slot />
      </div>
    </transition>
  </div>
</div>
</template>

<script>
import icoRotate from './ico-rotate.vue'

export default {
  name: 'lv1',
  data() {
    return {
      state: false,
      isIn: false
    }
  },
  components: {
    icoRotate
  },
  props: {
    text: String,
    lv1_index: Number
  },
  mounted() {
    // 单独指向效果
    // 如果地址栏没有lv1指向，打开 0 的lv1
    if (this.$route.query.lv1 == undefined && this.lv1_index == 0) {
      this.changeClose();
    } else if (this.$route.query.lv1 == this.lv1_index) {
      // 如果地址栏有lv1指向，打开指向的lv1
      this.changeClose();
    }
  },
  methods: {
    rotate() {
      this.$refs.icoRoutate.rotate();
    },
    stateChange() {
      this.state = !this.state
    },
    changeClose() {
      this.rotate()
      this.stateChange()
    }
  }
}
</script>

<style lang="less" scoped>
.lv1 {
  width: calc(100% - 30px);
  &:last-child {
    padding-bottom: 280px;
  }
  .bgc-hover {
    padding-left: 2px;
    padding-bottom: 10px;
    transition: all .15s;
    &:hover {
      border-radius: 35px;
      border-top-left-radius: 0;
      background-color: rgba(255, 255, 255, .33);
    }
    .text {
      cursor: pointer;
      font-size: @h4;
      font-weight: 800;
      user-select: none;
      margin-bottom: 30px;
      .hand {
        padding-left: 5px;
        transition: all .4s;
        display: inline-block;
      }
    }
    .text_hover {
      color: @qing;
    }
  }
}

.lv1-enter-active {
  animation: lv1-in .2s;
}
.lv1-leave-active {
  animation: lv1-in .3s reverse;
}
@keyframes lv1-in {
  0% {
    margin-top: -30px;
    opacity: 0;
  }
  100% {
    margin-top: 0px;
    opacity: 1;
  }
}
</style>