const router = createRouter({
  history: createWebHashHistory(),
  routes
})

// 页面即将离开时
router.beforeEach((to, from, next) => {
  // 有标题就赋标题值，没有就设置默认值
  if (to.meta.title) {
    // 做一层拷贝，将类型转化为 any 类型
    let title:any;
    title = to.meta.title
    
    document.title = title
  } else {
    document.title = '刘朝刚——个人网站'
  }

  // 更改小导航标题
  switch(to.name) {
    case 'Intro':
      store.commit('min_nav_title_change', '自我介绍')
      break
    // case 'Gossip':
    //   store.commit('min_nav_title_change', '闲聊时间')
    //   break
    default:
      // 如果路径中包含学习文档，小导航标题 学习文档
      if(to.path.search("/study/") == 0) {
        store.commit('min_nav_title_change', '学习文档')
      }
      // 如果路径中包含组件展览，小导航标题 组件展览
      else if(to.path.search("/expo/") == 0) {
        store.commit('min_nav_title_change', '组件展览')
      }
  }

  // 路由继续跳转
  next()
});

export default router